// ─── Types ───────────────────────────────────────────────────────────────────

export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, unknown>[];
  headers: string[];
  errors: CSVError[];
  filter: (predicate: (row: Record<string, unknown>) => boolean) => Record<string, unknown>[];
  sum: (column: string) => number;
  average: (column: string) => number;
  count: () => number;
  groupBy: (column: string) => Map<unknown, Record<string, unknown>[]>;
}

// ─── Field-level parser (handles quoting / escaping) ─────────────────────────

function parseFields(line: string, delimiter: string, quote: string): string[] {
  const fields: string[] = [];
  let i = 0;
  const len = line.length;

  while (i <= len) {
    if (i === len) {
      // trailing delimiter produced an empty field
      fields.push("");
      break;
    }

    if (line[i] === quote) {
      // ── quoted field ──
      let value = "";
      i++; // skip opening quote
      while (i < len) {
        if (line[i] === quote) {
          if (i + 1 < len && line[i + 1] === quote) {
            // escaped quote
            value += quote;
            i += 2;
          } else {
            // closing quote
            i++; // skip closing quote
            break;
          }
        } else {
          value += line[i];
          i++;
        }
      }
      fields.push(value);
      // skip delimiter (or we're at end of line)
      if (i < len && line[i] === delimiter) {
        i++;
        // if delimiter is last char, there's one more empty field
        if (i === len) {
          fields.push("");
          break;
        }
      } else {
        // either end-of-line or junk after closing quote – skip to next delimiter
        while (i < len && line[i] !== delimiter) i++;
        if (i < len) {
          i++; // skip delimiter
          if (i === len) {
            fields.push("");
            break;
          }
        } else {
          break;
        }
      }
    } else {
      // ── unquoted field ──
      let end = i;
      while (end < len && line[end] !== delimiter) end++;
      fields.push(line.substring(i, end));
      i = end + 1; // skip past delimiter
      if (i === len + 1) break; // delimiter was NOT there, we're done
      if (i === len) {
        // trailing delimiter
        fields.push("");
        break;
      }
    }
  }

  return fields;
}

// ─── Split input into lines respecting quoted fields that contain newlines ───

function splitLines(
  input: string,
  lineSeparator: string,
  quote: string,
): string[] {
  const lines: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;

  while (i < input.length) {
    const ch = input[i];

    if (inQuotes) {
      if (ch === quote) {
        if (i + 1 < input.length && input[i + 1] === quote) {
          current += ch + input[i + 1];
          i += 2;
          continue;
        } else {
          inQuotes = false;
          current += ch;
          i++;
          continue;
        }
      }
      current += ch;
      i++;
    } else {
      if (ch === quote) {
        inQuotes = true;
        current += ch;
        i++;
      } else if (input.startsWith(lineSeparator, i)) {
        lines.push(current);
        current = "";
        i += lineSeparator.length;
      } else {
        current += ch;
        i++;
      }
    }
  }

  if (current.length > 0) {
    lines.push(current);
  }

  return lines;
}

// ─── Type coercion ───────────────────────────────────────────────────────────

function coerce(value: string): unknown {
  // null / empty
  if (value === "" || value === "null" || value === "NULL") return null;

  // boolean
  const lower = value.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;

  // number – must match the ENTIRE string
  if (/^-?\d+$/.test(value)) {
    const n = Number(value);
    if (Number.isSafeInteger(n)) return n;
  }
  if (/^-?\d+\.\d+$/.test(value)) {
    return parseFloat(value);
  }

  return value;
}

// ─── Main entry point ────────────────────────────────────────────────────────

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator ?? "\n";

  const rows: Record<string, unknown>[] = [];
  const errors: CSVError[] = [];

  // Handle empty / whitespace-only input
  const trimmed = input.trim();
  if (trimmed.length === 0) {
    return buildResult([], [], errors);
  }

  const lines = splitLines(trimmed, lineSeparator, quote);

  if (lines.length === 0) {
    return buildResult([], [], errors);
  }

  // First line → headers
  const headers = parseFields(lines[0], delimiter, quote).map((h) => h.trim());

  // Remaining lines → data rows
  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];

    // skip blank lines
    if (line.trim() === "") continue;

    const fields = parseFields(line, delimiter, quote);

    if (fields.length !== headers.length) {
      errors.push({
        row: i + 1, // 1-indexed, header is row 1
        message: `Expected ${headers.length} fields but got ${fields.length}`,
      });
      // still produce a row with what we have – pad / truncate
      const row: Record<string, unknown> = {};
      for (let h = 0; h < headers.length; h++) {
        row[headers[h]] = h < fields.length ? coerce(fields[h]) : null;
      }
      rows.push(row);
      continue;
    }

    const row: Record<string, unknown> = {};
    for (let h = 0; h < headers.length; h++) {
      row[headers[h]] = coerce(fields[h]);
    }
    rows.push(row);
  }

  return buildResult(rows, headers, errors);
}

// ─── Build the result object with helper methods ─────────────────────────────

function buildResult(
  rows: Record<string, unknown>[],
  headers: string[],
  errors: CSVError[],
): CSVResult {
  return {
    rows,
    headers,
    errors,

    filter(predicate: (row: Record<string, unknown>) => boolean) {
      return rows.filter(predicate);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") total += v;
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") {
          total += v;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<unknown, Record<string, unknown>[]> {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of rows) {
        const key = row[column];
        let group = map.get(key);
        if (!group) {
          group = [];
          map.set(key, group);
        }
        group.push(row);
      }
      return map;
    },
  };
}
